module RefModule(
    input clk,
    input reset,
    output reg [2:0] q
);

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (reset) begin
            // Synchronous reset: Reset the counter to 3'b111
            q <= 3'b111;
        end else begin
            // Binary down-counter: Decrement the counter
            q <= q - 1;
        end
    end

endmodule
